#!/usr/bin/env python3
"""
Robust i18n key insertion — finds each language block by opener,
walks to its closing brace, inserts keys just before it.
"""
import re, shutil, os

SRC = "src/App.jsx"
shutil.copy(SRC, SRC + ".pre-i18n2")

with open(SRC, "r", encoding="utf-8") as f:
    src = f.read()

def find_lang_block_end(src, lang_code):
    """Find the position just before the closing }, of a language block."""
    # Find the lang opener e.g. \nen:{ or ,en:{
    pat = re.compile(r'[\n,]\s*' + re.escape(lang_code) + r'\s*:\s*\{')
    m = pat.search(src)
    if not m:
        return None
    
    # Walk from the opening { counting depth
    start = m.end() - 1  # position of {
    depth = 0
    i = start
    in_str = False
    str_ch = None
    
    while i < len(src):
        c = src[i]
        if in_str:
            if c == '\\':
                i += 2
                continue
            if c == str_ch:
                in_str = False
        else:
            if c in ('"', "'", '`'):
                in_str = True
                str_ch = c
            elif c == '{':
                depth += 1
            elif c == '}':
                depth -= 1
                if depth == 0:
                    return i  # position of closing }
        i += 1
    return None

