inserted = 0
for lang in LANGS:
    end_pos = find_lang_block_end(src, lang)
    if end_pos is None:
        print(f"  ⚠  {lang}: block not found")
        continue
    
    keys = NEW_KEYS.get(lang, {})
    # Build comma-separated key:value string
    key_str = "," + ",".join(f'{k}:"{v}"' for k, v in keys.items())
    
    # Insert before the closing }
    src = src[:end_pos] + key_str + src[end_pos:]
    print(f"  ✓  {lang}: {len(keys)} keys added")
    inserted += 1

with open(SRC, "w", encoding="utf-8") as f:
    f.write(src)

print(f"\n✅ Done — {inserted} languages updated")
print("Run: npm run dev")
